#include <stdio.h>

int main() {
    int age = 16;

    if (age >= 18) {
        printf("You can vote!\n");
    } else {
        printf("You are too young to vote.\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int score = 85;

    if (score >= 90) {
        printf("Grade: A");
    } else if (score >= 80) {
        printf("Grade: B");
    } else if (score >= 70) {
        printf("Grade: C");
    } else {
        printf("Grade: F");
    }

    return 0;
}
